1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const countLiveNeighbors = (cell: Cell, liveCells: ReadonlySet<string>): number =>
12	  NEIGHBOR_OFFSETS.filter(([dx, dy]) =>
13	    liveCells.has(cellKey([cell[0] + dx, cell[1] + dy])),
14	  ).length;
15	
16	const neighborsOf = (cell: Cell): Cell[] =>
17	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [cell[0] + dx, cell[1] + dy]);
18	
19	const isAliveNextGeneration = (
20	  cell: Cell,
21	  isCurrentlyAlive: boolean,
22	  liveCells: ReadonlySet<string>,
23	): boolean => {
24	  const neighborCount = countLiveNeighbors(cell, liveCells);
25	  return isCurrentlyAlive
26	    ? neighborCount === 2 || neighborCount === 3
27	    : neighborCount === 3;
28	};
29	
30	const candidateCells = (cells: Cell[]): Map<string, Cell> => {
31	  const candidates = new Map<string, Cell>();
32	  for (const cell of cells) {
33	    for (const candidate of [cell, ...neighborsOf(cell)]) {
34	      candidates.set(cellKey(candidate), candidate);
35	    }
36	  }
37	  return candidates;
38	};
39	
40	export const nextGeneration = (cells: Cell[]): Cell[] => {
41	  const liveCells = new Set(cells.map(cellKey));
42	  const result: Cell[] = [];
43	  for (const [key, cell] of candidateCells(cells)) {
44	    if (isAliveNextGeneration(cell, liveCells.has(key), liveCells)) {
45	      result.push(cell);
46	    }
47	  }
48	  return result;
49	};
50

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent cells each with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a live cell alive when it has 2 live neighbors (survival)", () => {
15	    // Vertical blinker: center cell (0,1) has 2 live neighbors and survives
16	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
17	    expect(result).toContainEqual([0, 1]);
18	  });
19	  it("kills a live cell with more than 3 live neighbors (overpopulation)", () => {
20	    // Center (1,1) has 4 live neighbors and dies
21	    const cells: Cell[] = [
22	      [0, 0], [1, 0], [2, 0],
23	      [0, 1], [1, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ];
26	    const result = nextGeneration(cells);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
29	  it("brings a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
30	    // From spec rule 4: dead cell (1,1) has exactly 3 live neighbors and becomes alive
31	    const cells: Cell[] = [[0, 0], [1, 0], [0, 1]];
32	    const result = nextGeneration(cells);
33	    expect(result).toContainEqual([1, 1]);
34	  });
35	  it("preserves a block still life across a generation", () => {
36	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
37	    const result = nextGeneration(block);
38	    expect(result).toHaveLength(4);
39	    expect(result).toContainEqual([0, 0]);
40	    expect(result).toContainEqual([1, 0]);
41	    expect(result).toContainEqual([0, 1]);
42	    expect(result).toContainEqual([1, 1]);
43	  });
44	  it("oscillates a vertical blinker into a horizontal blinker", () => {
45	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
46	    const result = nextGeneration(vertical);
47	    expect(result).toHaveLength(3);
48	    expect(result).toContainEqual([-1, 1]);
49	    expect(result).toContainEqual([0, 1]);
50	    expect(result).toContainEqual([1, 1]);
51	  });
52	  it("handles negative coordinates correctly", () => {
53	    // Block still life at negative coordinates
54	    const block: Cell[] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
55	    const result = nextGeneration(block);
56	    expect(result).toHaveLength(4);
57	    expect(result).toContainEqual([-5, -5]);
58	    expect(result).toContainEqual([-4, -5]);
59	    expect(result).toContainEqual([-5, -4]);
60	    expect(result).toContainEqual([-4, -4]);
61	  });
62	});
